import { AbstractControl, ValidationErrors, ValidatorFn, Validators, FormBuilder, ReactiveFormsModule } from '@angular/forms';
import { Component, inject } from '@angular/core';

function passwordStrength(): ValidatorFn {
  return (c: AbstractControl): ValidationErrors | null => {
    const v = String(c.value ?? '');
    if (v.length < 8) return { tooShort: true };
    if (!/\d/.test(v)) return { noDigit: true };
    return null;
  };
}

@Component({
  selector: 'app-register',
  standalone: true,
  imports: [ReactiveFormsModule],
  template: `
    <form [formGroup]="form" (ngSubmit)="onSubmit()">
      <input formControlName="name" placeholder="Name" />
      @if (form.controls.name.touched && form.controls.name.errors?.['required']) {
        <small>Name is required.</small>
      }

      <input formControlName="email" placeholder="Email" />
      @if (form.controls.email.touched && form.controls.email.errors?.['email']) {
        <small>Invalid email.</small>
      }

      <input formControlName="password" placeholder="Password" type="password" />
      @if (form.controls.password.touched) {
        @if (form.controls.password.errors?.['tooShort']) { <small>Min 8 chars.</small> }
        @if (form.controls.password.errors?.['noDigit'])  { <small>Needs a digit.</small> }
      }

      <button type="submit" [disabled]="form.invalid">Submit</button>
    </form>
  `,
})
export class RegisterComponent {
  private fb = inject(FormBuilder);
  form = this.fb.group({
    name:     ['', Validators.required],
    email:    ['', [Validators.required, Validators.email]],
    password: ['', [Validators.required, passwordStrength()]],
  });
