import { Component, inject } from '@angular/core';
import { FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';

@Component({
  selector: 'app-order',
  standalone: true,
  imports: [ReactiveFormsModule],
  template: `
    <form [formGroup]="form" (ngSubmit)="submit()">
      <select formControlName="type">
        <option value="standard">Standard</option>
        <option value="priority">Priority</option>
      </select>
      <input formControlName="notes"     placeholder="Notes (priority only)" />
      <input formControlName="qty"       type="number" />
      <input formControlName="unitPrice" type="number" />
      <p>Line total: {{ form.controls.lineTotal.value }}</p>
      <p>Final total: {{ form.controls.finalTotal.value }}</p>
      <button [disabled]="form.invalid">Submit</button>
    </form>
  `,
})
export class OrderComponent {
  private fb = inject(FormBuilder);
  form = this.fb.group({
    type:       ['standard', Validators.required],
    notes:      [''],
    qty:        [1, [Validators.required, Validators.min(1)]],
    unitPrice:  [0, [Validators.required, Validators.min(0)]],
    lineTotal:  [{ value: 0, disabled: true }],
    finalTotal: [{ value: 0, disabled: true }],
  });

  constructor() {
    const f = this.form.controls;

    f.type.valueChanges.subscribe(t => {
      if (t === 'priority') f.notes.setValidators([Validators.required]);
      else                  f.notes.clearValidators();
      f.notes.updateValueAndValidity();
    });

    const recalc = () => {
      const line  = (f.qty.value ?? 0) * (f.unitPrice.value ?? 0);
      const final = line > 1000 ? line * 0.9 : line;
      f.lineTotal.setValue(line,  { emitEvent: false });
      f.finalTotal.setValue(final, { emitEvent: false });
    };
    f.qty.valueChanges.subscribe(recalc);
    f.unitPrice.valueChanges.subscribe(recalc);
  }

  submit() { console.log(this.form.getRawValue()); }
}
