import { Component, inject, signal } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';

interface Role { id: string; label: string; }

@Component({
  selector: 'app-create-user',
  standalone: true,
  imports: [ReactiveFormsModule],
  template: `
    <form [formGroup]="form" (ngSubmit)="submit()">
      <input formControlName="name" placeholder="Name" />

      @if (rolesState() === 'loading') { <p>Loading roles…</p> }
      @else if (rolesState() === 'error') {
        <p>Couldn't load roles. <button type="button" (click)="loadRoles()">Retry</button></p>
      }
      @else {
        <select formControlName="roleId">
          @for (r of roles(); track r.id) {
            <option [value]="r.id">{{ r.label }}</option>
          }
        </select>
      }

      <button [disabled]="form.invalid || submitting()">
        {{ submitting() ? 'Saving…' : 'Create' }}
      </button>
      @if (msg()) { <p [style.color]="ok() ? 'green' : 'red'">{{ msg() }}</p> }
    </form>
  `,
})
export class CreateUserComponent {
  private http = inject(HttpClient);
  private fb   = inject(FormBuilder);

  form = this.fb.group({
    name:   ['', Validators.required],
    roleId: ['', Validators.required],
  });

  roles      = signal<Role[]>([]);
  rolesState = signal<'loading' | 'ready' | 'error'>('loading');
  submitting = signal(false);
  msg        = signal('');
  ok         = signal(false);

  constructor() { this.loadRoles(); }

  loadRoles() {
    this.rolesState.set('loading');
    this.http.get<Role[]>('/api/roles').subscribe({
      next: rs => { this.roles.set(rs); this.rolesState.set('ready'); },
      error: () => this.rolesState.set('error'),
    });
  }

  submit() {
    this.submitting.set(true);
    this.http.post('/api/users', this.form.value).subscribe({
      next: () => { this.msg.set('User created'); this.ok.set(true); },
      error: () => { this.msg.set('Failed to create user'); this.ok.set(false); },
      complete: () => this.submitting.set(false),
    });
  }
}
