import { Component, DestroyRef, inject, signal } from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { HttpClient } from '@angular/common/http';
import { AbstractControl, AsyncValidatorFn, FormBuilder, ReactiveFormsModule, ValidationErrors, Validators } from '@angular/forms';
import { Observable, debounceTime, distinctUntilChanged, map, of, switchMap } from 'rxjs';

function uniqueUsername(http: HttpClient): AsyncValidatorFn {
  return (c: AbstractControl): Observable<ValidationErrors | null> => {
    const v = String(c.value ?? '').trim();
    if (!v) return of(null);
    return http
      .get<{ available: boolean }>('/api/check-username', { params: { u: v } })
      .pipe(map(r => (r.available ? null : { taken: true })));
  };
}

@Component({
  selector: 'app-async-form',
  standalone: true,
  imports: [ReactiveFormsModule],
  template: `
    <form [formGroup]="form">
      <input formControlName="username" placeholder="Username" />
      @if (form.controls.username.pending) { <small>Checking…</small> }
      @if (form.controls.username.errors?.['taken']) { <small>Taken.</small> }

      <select formControlName="country">
        <option value="">Pick…</option>
        <option value="EG">Egypt</option>
        <option value="AE">UAE</option>
      </select>

      <select formControlName="city">
        @for (c of cities(); track c) { <option [value]="c">{{ c }}</option> }
      </select>
    </form>
  `,
})
export class AsyncFormComponent {
  private http        = inject(HttpClient);
  private fb          = inject(FormBuilder);
  private destroyRef  = inject(DestroyRef);

  cities = signal<string[]>([]);

  form = this.fb.group({
    username: ['', { validators: [Validators.required], asyncValidators: [uniqueUsername(this.http)], updateOn: 'change' }],
    country:  [''],
    city:     [''],
  });

  constructor() {
    this.form.controls.country.valueChanges
      .pipe(
        debounceTime(150),
        distinctUntilChanged(),
        switchMap(c => c ? this.http.get<string[]>('/api/cities', { params: { country: c } }) : of([])),
        takeUntilDestroyed(this.destroyRef),
      )
      .subscribe(list => this.cities.set(list));
  }
}
